),
"Left Mastectomy Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Status Post Left Mastectomy (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Status Post Left Mastectomy (qicore-condition-problems-health-concerns)" UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Unilateral Mastectomy, Unspecified Laterality (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Unilateral Mastectomy, Unspecified Laterality (qicore-condition-problems-health-concerns)") AS UnilateralMastectomyDiagnosis WHERE fhirpath_bool(UnilateralMastectomyDiagnosis.resource, 'bodySite.coding.where(system=''http://snomed.info/sct'' and code=''7771000'').exists()'))) AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS LeftMastectomy WHERE LEFT(CAST(intervalStart(CASE WHEN fhirpath_text(LeftMastectomy.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LeftMastectomy.resource, 'onsetDateTime'), fhirpath_text(LeftMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(LeftMastectomy.resource, 'recordedDate')), fhirpath_text(LeftMastectomy.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LeftMastectomy.resource, 'onsetDateTime'), fhirpath_text(LeftMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(LeftMastectomy.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LeftMastectomy.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LeftMastectomy.resource, 'onsetDateTime'), fhirpath_text(LeftMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(LeftMastectomy.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LeftMastectomy.resource, 'onsetDateTime'), fhirpath_text(LeftMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(LeftMastectomy.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), 10) <= LEFT(CAST(CAST('2026-12-31T23:59:59.999' AS VARCHAR) AS VARCHAR), 10)
),
"Left Mastectomy Procedure" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Unilateral Mastectomy Left" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS UnilateralMastectomyLeftPerformed WHERE LEFT(CAST(intervalEnd(CASE WHEN fhirpath_text(UnilateralMastectomyLeftPerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(UnilateralMastectomyLeftPerformed.resource, 'performed')), '{') THEN fhirpath_text(UnilateralMastectomyLeftPerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(UnilateralMastectomyLeftPerformed.resource, 'performed'), fhirpath_text(UnilateralMastectomyLeftPerformed.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), 10) <= LEFT(CAST(CAST('2026-12-31T23:59:59.999' AS VARCHAR) AS VARCHAR), 10)
),
"October 1 Two Years Prior to the Measurement Period" AS (
SELECT p.patient_id, printf('%04d-%02d-%02dT%02d:%02d:%02d.%03d', CASE WHEN LENGTH(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) - INTERVAL '2 year' AS VARCHAR), ' ', 'T')) >= 4 THEN CAST(SUBSTR(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) - INTERVAL '2 year' AS VARCHAR), ' ', 'T'), 1, 4) AS INTEGER) ELSE NULL END, 10, 1, 0, 0, 0, 0) || printf('%+03.0f:00', CAST(0 AS DOUBLE)) AS value FROM _patients AS p
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Mammography" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS Mammogram WHERE Mammogram.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(Mammogram.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Mammogram.resource, 'effective')), '{') THEN fhirpath_text(Mammogram.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(Mammogram.resource, 'effective'), fhirpath_text(Mammogram.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) BETWEEN CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST((SELECT sub.value FROM "October 1 Two Years Prior to the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST((SELECT sub.value FROM "October 1 Two Years Prior to the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST((SELECT sub.value FROM "October 1 Two Years Prior to the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)))
),
"Right Mastectomy Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM ((SELECT * FROM (SELECT patient_id, resource FROM "Condition: Status Post Right Mastectomy (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Status Post Right Mastectomy (qicore-condition-problems-health-concerns)") AS RightMastectomyProcedure) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Unilateral Mastectomy, Unspecified Laterality (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Unilateral Mastectomy, Unspecified Laterality (qicore-condition-problems-health-concerns)") AS UnilateralMastectomyDiagnosis WHERE fhirpath_bool(UnilateralMastectomyDiagnosis.resource, 'bodySite.coding.where(system=''http://snomed.info/sct'' and code=''24028007'').exists()'))) AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS RightMastectomy WHERE LEFT(CAST(intervalStart(CASE WHEN fhirpath_text(RightMastectomy.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(RightMastectomy.resource, 'onsetDateTime'), fhirpath_text(RightMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(RightMastectomy.resource, 'recordedDate')), fhirpath_text(RightMastectomy.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(RightMastectomy.resource, 'onsetDateTime'), fhirpath_text(RightMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(RightMastectomy.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(RightMastectomy.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(RightMastectomy.resource, 'onsetDateTime'), fhirpath_text(RightMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(RightMastectomy.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(RightMastectomy.resource, 'onsetDateTime'), fhirpath_text(RightMastectomy.resource, 'onsetPeriod.start'), fhirpath_text(RightMastectomy.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), 10) <= LEFT(CAST(CAST('2026-12-31T23:59:59.999' AS VARCHAR) AS VARCHAR), 10)
),
"Right Mastectomy Procedure" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Unilateral Mastectomy Right" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS UnilateralMastectomyRightPerformed WHERE LEFT(CAST(intervalEnd(CASE WHEN fhirpath_text(UnilateralMastectomyRightPerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(UnilateralMastectomyRightPerformed.resource, 'performed')), '{') THEN fhirpath_text(UnilateralMastectomyRightPerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(UnilateralMastectomyRightPerformed.resource, 'performed'), fhirpath_text(UnilateralMastectomyRightPerformed.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), 10) <= LEFT(CAST(CAST('2026-12-31T23:59:59.999' AS VARCHAR) AS VARCHAR), 10)
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Hospice.Has Hospice Services" AS sub WHERE sub.patient_id = p.patient_id) OR (EXISTS (SELECT 1 FROM "Right Mastectomy Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Right Mastectomy Procedure" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "Left Mastectomy Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Left Mastectomy Procedure" AS sub WHERE sub.patient_id = p.patient_id)) OR EXISTS (SELECT 1 FROM "Bilateral Mastectomy Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Bilateral Mastectomy Procedure" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older with Advanced Illness and Frailty" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older Living Long Term in a Nursing Home" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "PalliativeCare.Has Palliative Care in the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
),
"Stratification 1" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 42 AND 51
),
"Stratification 2" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 52 AND 74
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
